def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    from pptx.enum.shapes import PP_PLACEHOLDER
    from pptx.oxml.ns import qn
    import difflib
    import os

    title_text = "Texts and Human Experiences"

    # Use globally-defined paths; ensure they exist
    global original_ppt_path, modified_ppt_path  # noqa: F821
    try:  # runtime guard
        _ = original_ppt_path  # noqa: F821
        _ = modified_ppt_path  # noqa: F821
    except NameError:
        return "Global original_ppt_path / modified_ppt_path not defined in runtime scope.", 0.0

    # Load original and modified presentations
    orig_prs = Presentation(original_ppt_path)
    mod_prs = Presentation(modified_ppt_path)
    # Get first slide from both
    orig_slide = orig_prs.slides[0]
    mod_slide = mod_prs.slides[0]

    def find_title_shape(slide):
        phrase = title_text.strip().lower()
        candidates = []
        for idx, shape in enumerate(slide.shapes):
            if not getattr(shape, 'has_text_frame', False):
                continue
            try:
                raw_text = shape.text_frame.text or ""
            except Exception:
                continue
            text_lower = raw_text.lower()
            contains_phrase = phrase in text_lower
            tokens = [t for t in phrase.split() if t]
            token_overlap = sum(1 for t in tokens if t in text_lower)
            placeholder_rank = 0
            ph_type = None
            if getattr(shape, 'is_placeholder', False):
                try:
                    ph_type = shape.placeholder_format.type
                    if ph_type in (PP_PLACEHOLDER.TITLE, getattr(PP_PLACEHOLDER, 'CENTER_TITLE', None)):
                        placeholder_rank = 3
                    else:
                        placeholder_rank = 1
                except Exception:
                    pass
            # Heuristic score
            score = (10 if contains_phrase else 0) + placeholder_rank*5 + token_overlap + len(raw_text)/120.0
            candidates.append((score, idx, shape, raw_text[:120].replace('\n',' / ')))
        if not candidates:
            return None
        candidates.sort(key=lambda x: x[0], reverse=True)
        if os.environ.get("DEBUG_FONT") == "1":
            for sc, i, sh, snip in candidates:
                try:
                    print(f"[FIND] score={sc:.2f} idx={i} placeholder={getattr(sh.placeholder_format,'type',None) if getattr(sh,'is_placeholder',False) else None} text='{snip}'")
                except Exception:
                    pass
        return candidates[0][2]

    orig_title = find_title_shape(orig_slide)
    mod_title = find_title_shape(mod_slide)
    if orig_title is None or mod_title is None:
        return "Could not locate the main title in one or both presentations.", 0.0

    # Inheritance-aware effective font size resolution.
    # PowerPoint font size precedence roughly:
    #   Run rPr.sz > Paragraph a:pPr/a:defRPr.sz > Layout text style > Master text style.
    # python-pptx only exposes explicitly-set sizes; inherited ones stay None, so we need XML inspection.
    NS = {"p": "http://schemas.openxmlformats.org/presentationml/2006/main",
          "a": "http://schemas.openxmlformats.org/drawingml/2006/main"}

    def _presentation_default_style_size(shape, level):
        """Search presentation-level defaultTextStyle for a size (rare but possible)."""
        try:
            pres_el = shape.part.package.presentation_part.element
        except Exception:
            return None
        # lvl is 1-based
        paths = [
            f"./p:defaultTextStyle/a:lvl{level}pPr/a:defRPr/@sz",
            f"./p:defaultTextStyle/a:defPPr/a:defRPr/@sz",
        ]
        for xp in paths:
            try:
                vals = pres_el.xpath(xp, namespaces=NS)
            except TypeError:
                vals = pres_el.xpath(xp)
            if vals:
                try:
                    return int(vals[0]) / 100.0
                except ValueError:
                    return None
        return None

    def _run_explicit_size(run):
        rPr = run._r.rPr  # do NOT auto-create
        if rPr is not None:
            sz = rPr.get("sz")  # value stored in 1/100 points
            if sz:
                return int(sz)/100.0
        return None

    def _para_default_size(para):
        pPr = para._p.pPr
        if pPr is not None:
            defRPr = pPr.find(qn('a:defRPr'))
            if defRPr is not None:
                sz = defRPr.get('sz')
                if sz:
                    return int(sz)/100.0
        return None

    def _para_end_size(para):
        """Size specified on a:endParaRPr (sometimes used)."""
        pPr = para._p.pPr
        if pPr is not None:
            endRPr = pPr.find(qn('a:endParaRPr'))
            if endRPr is not None:
                sz = endRPr.get('sz')
                if sz:
                    try:
                        return int(sz)/100.0
                    except ValueError:
                        return None
        return None

    def _shape_lst_style_size(shape, level):
        """Check shape's own a:lstStyle hierarchy for size (not previously queried)."""
        try:
            txBody = shape.text_frame._txBody  # oxml element
        except Exception:
            return None
        if txBody is None:
            return None
        # 1. Level-specific
        xp_level = f"./a:lstStyle/a:lvl{level}pPr/a:defRPr/@sz"
        # 2. Fallback default paragraph formatting in lstStyle
        xp_default = "./a:lstStyle/a:defPPr/a:defRPr/@sz"
        for xp in (xp_level, xp_default):
            try:
                vals = txBody.xpath(xp, namespaces=NS)
            except TypeError:
                vals = txBody.xpath(xp)
            if vals:
                try:
                    return int(vals[0]) / 100.0
                except ValueError:
                    return None
        return None

    def _style_size(shape, level):
        # level: 1-based paragraph level (para.level is 0-based)
        slide_layout = shape.part.slide_layout if hasattr(shape.part, 'slide_layout') else None
        if slide_layout is None:
            return None
        layout_el = slide_layout.element
        master_el = slide_layout.part.slide_master.element

        def pick(container_el, style_tag):
            # XPath for lvlNpPr where N=level
            xp = f"./p:{style_tag}/a:lvl{level}pPr/a:defRPr/@sz"
            try:
                vals = container_el.xpath(xp, namespaces=NS)  # newer python-pptx / lxml style
            except TypeError:
                # Some versions expose xpath() wrapper without namespaces kw
                vals = container_el.xpath(xp)
            # Fallback: namespace-insensitive search if nothing found
            if not vals:
                alt = (f".//*[local-name()='{style_tag}']/*[local-name()='lvl{level}pPr']" \
                       f"/*[local-name()='defRPr']/@sz")
                try:
                    vals = container_el.xpath(alt)
                except Exception:
                    pass
            if vals:
                try:
                    return int(vals[0]) / 100.0
                except ValueError:
                    return None
            # Default paragraph style in style_tag (defPPr)
            xp_def = f"./p:{style_tag}/a:defPPr/a:defRPr/@sz"
            try:
                vals2 = container_el.xpath(xp_def, namespaces=NS)
            except TypeError:
                vals2 = container_el.xpath(xp_def)
            if not vals2:
                alt_def = (f".//*[local-name()='{style_tag}']/*[local-name()='defPPr']" \
                           f"/*[local-name()='defRPr']/@sz")
                try:
                    vals2 = container_el.xpath(alt_def)
                except Exception:
                    vals2 = []
            if vals2:
                try:
                    return int(vals2[0]) / 100.0
                except ValueError:
                    return None
            return None

        # Decide probable style set (title vs body). Could be expanded for ctrTitle, etc.
        style_tags = ["bodyStyle"]
        if getattr(shape, 'is_placeholder', False):
            try:
                ph_type = shape.placeholder_format.type
                # Treat both TITLE and CENTER_TITLE as titleStyle
                if ph_type in (PP_PLACEHOLDER.TITLE, getattr(PP_PLACEHOLDER, 'CENTER_TITLE', None)):
                    style_tags = ["titleStyle", "bodyStyle"]  # prefer title style
            except Exception:
                pass

        for tag in style_tags:
            for container in (layout_el, master_el):
                sz = pick(container, tag)
                if sz is not None:
                    return sz
        return None

    def _autofit_scale(shape):
        """Return fontScale factor if normAutofit present, else 1.0"""
        try:
            txBody = shape.text_frame._txBody
            try:
                els = txBody.xpath('./a:bodyPr/a:normAutofit', namespaces=NS)
            except TypeError:
                els = txBody.xpath('./a:bodyPr/a:normAutofit')
            if els:
                el = els[0]
                val = el.get('fontScale')
                if val:
                    # spec: thousandths of a percent, so 100% == 100000
                    return int(val)/100000.0
        except Exception:
            pass
        return 1.0

    def get_text_run_details(shape):
        """Get detailed information about each text run with its font size and text content."""
        if not shape.has_text_frame:
            return []

        text_runs = []
        scale = _autofit_scale(shape)

        for para in shape.text_frame.paragraphs:
            para_level = (para.level or 0) + 1

            # Handle paragraphs with runs
            for run in para.runs:
                text_content = run.text
                if not text_content.strip():  # Skip empty runs
                    continue

                sz = (_run_explicit_size(run) or
                      _para_default_size(para) or
                      _para_end_size(para) or
                      _shape_lst_style_size(shape, para_level) or
                      _style_size(shape, para_level) or
                      _presentation_default_style_size(shape, para_level))

                if sz:
                    effective_size = sz * scale
                    text_runs.append({
                        'text': text_content,
                        'size': effective_size,
                        'char_count': len(text_content)
                    })

            # Handle paragraphs with no runs but text
            if not para.runs and para.text.strip():
                sz = (_para_default_size(para) or
                      _para_end_size(para) or
                      _shape_lst_style_size(shape, para_level) or
                      _style_size(shape, para_level) or
                      _presentation_default_style_size(shape, para_level))

                if sz:
                    effective_size = sz * scale
                    text_runs.append({
                        'text': para.text,
                        'size': effective_size,
                        'char_count': len(para.text)
                    })

        return text_runs

    def calculate_partial_score(orig_runs, mod_runs):
        """Calculate partial score based on which text segments had font size increases."""
        if not orig_runs or not mod_runs:
            return 0.0, "Could not extract text run details from one or both presentations."

        # Create a mapping of text content to font sizes for comparison
        orig_text_sizes = {run['text']: run['size'] for run in orig_runs}
        mod_text_sizes = {run['text']: run['size'] for run in mod_runs}

        # Calculate total character count for weighting
        total_chars = sum(run['char_count'] for run in orig_runs)
        increased_chars = 0
        unchanged_chars = 0
        decreased_chars = 0

        changes_detected = []

        # Check each text segment for font size changes
        for text, orig_size in orig_text_sizes.items():
            if text in mod_text_sizes:
                mod_size = mod_text_sizes[text]
                char_count = next((run['char_count'] for run in orig_runs if run['text'] == text), 0)

                if mod_size > orig_size + 0.1:  # Small tolerance for floating point comparison
                    increased_chars += char_count
                    changes_detected.append(f"'{text}': {orig_size:.1f}pt → {mod_size:.1f}pt (increased)")
                elif mod_size < orig_size - 0.1:
                    decreased_chars += char_count
                    changes_detected.append(f"'{text}': {orig_size:.1f}pt → {mod_size:.1f}pt (decreased)")
                else:
                    unchanged_chars += char_count
                    changes_detected.append(f"'{text}': {orig_size:.1f}pt (unchanged)")

        # Check for new text segments in modified version
        for text, mod_size in mod_text_sizes.items():
            if text not in orig_text_sizes:
                char_count = next((run['char_count'] for run in mod_runs if run['text'] == text), 0)
                changes_detected.append(f"'{text}': new text at {mod_size:.1f}pt")

        # Calculate score based on proportion of text with increased font size
        if total_chars == 0:
            return 0.0, "No text content found to analyze."

        increase_ratio = increased_chars / total_chars

        # Determine score and reason
        if increase_ratio >= 0.9:  # 90% or more of text increased
            score = 1.0
            reason = f"Font size increased for {increase_ratio*100:.1f}% of text. Changes: {'; '.join(changes_detected)}"
        elif increase_ratio >= 0.5:  # 50-89% of text increased
            score = 0.8
            reason = f"Font size increased for {increase_ratio*100:.1f}% of text (partial completion). Changes: {'; '.join(changes_detected)}"
        elif increase_ratio >= 0.25:  # 25-49% of text increased
            score = 0.5
            reason = f"Font size increased for {increase_ratio*100:.1f}% of text (limited completion). Changes: {'; '.join(changes_detected)}"
        elif increase_ratio > 0:  # Some text increased
            score = 0.3
            reason = f"Font size increased for {increase_ratio*100:.1f}% of text (minimal completion). Changes: {'; '.join(changes_detected)}"
        else:  # No text increased
            if decreased_chars > 0:
                score = 0.0
                reason = f"Font size was decreased rather than increased. Changes: {'; '.join(changes_detected)}"
            else:
                score = 0.0
                reason = f"No font size increases detected. Changes: {'; '.join(changes_detected)}"

        return score, reason

    # Get detailed text run information from both presentations
    orig_runs = get_text_run_details(orig_title)
    mod_runs = get_text_run_details(mod_title)

    # Calculate partial score based on text-level changes
    score, reason = calculate_partial_score(orig_runs, mod_runs)

    return reason, score

def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    import difflib
    title_text = "Texts and Human Experiences"
    orig_prs = Presentation(original_ppt_path)
    mod_prs = Presentation(modified_ppt_path)
    orig_slide = orig_prs.slides[0]
    mod_slide = mod_prs.slides[0]
    def find_title_shape(slide):
        for shape in slide.shapes:
            if shape.has_text_frame:
                if title_text.strip().lower() in shape.text.strip().lower():
                    return shape
        return None
    orig_title = find_title_shape(orig_slide)
    mod_title = find_title_shape(mod_slide)
    if orig_title is None or mod_title is None:
        return "Could not locate the main title in one or both presentations.", 0.0
    orig_text = orig_title.text.strip()
    mod_text = mod_title.text.strip()
    # Use sequence matcher to check for changes
    if orig_text == mod_text:
        return "Title text unchanged.", 1.0
    elif difflib.SequenceMatcher(None, orig_text, mod_text).ratio() > 0.95:
        return "Title text changed minimally (likely whitespace), partial credit.", 0.5
    else:
        return f"Title text changed from '{orig_text}' to '{mod_text}'.", 0.0

def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    orig_prs = Presentation(original_ppt_path)
    mod_prs = Presentation(modified_ppt_path)
    orig_slide = orig_prs.slides[0]
    mod_slide = mod_prs.slides[0]
    title_text = "Texts and Human Experiences"
    # Find main title shape index in both slides
    def title_shape_idx(slide):
        for i, shape in enumerate(slide.shapes):
            if shape.has_text_frame:
                if title_text.strip().lower() in shape.text.strip().lower():
                    return i
        return None
    orig_title_idx = title_shape_idx(orig_slide)
    mod_title_idx = title_shape_idx(mod_slide)
    def shape_summary(shape):
        if shape.has_text_frame:
            return shape.text.strip()
        if hasattr(shape, 'name'):
            return shape.name
        return str(type(shape))
    # Compare all shapes except the title shape
    unchanged = True
    for i in range(len(orig_slide.shapes)):
        if i == orig_title_idx:
            continue
        orig_shape_sum = shape_summary(orig_slide.shapes[i])
        if i < len(mod_slide.shapes):
            mod_shape_sum = shape_summary(mod_slide.shapes[i])
        else:
            unchanged = False
            break
        if orig_shape_sum != mod_shape_sum:
            unchanged = False
            break
    if unchanged and len(orig_slide.shapes) == len(mod_slide.shapes):
        return "All other shapes on first slide unchanged.", 1.0
    else:
        return "Other shapes on first slide have been changed.", 0.0

def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    orig_prs = Presentation(original_ppt_path)
    mod_prs = Presentation(modified_ppt_path)
    # Ignore first slide
    if len(orig_prs.slides) != len(mod_prs.slides):
        return "Number of slides changed.", 0.0
    unchanged = True
    for i in range(1, len(orig_prs.slides)):
        orig_slide = orig_prs.slides[i]
        mod_slide = mod_prs.slides[i]
        # Compare text content for all shapes
        for j in range(len(orig_slide.shapes)):
            orig_shape = orig_slide.shapes[j]
            mod_shape = mod_slide.shapes[j] if j < len(mod_slide.shapes) else None
            if mod_shape is None:
                unchanged = False
                break
            if orig_shape.has_text_frame and mod_shape.has_text_frame:
                if orig_shape.text.strip() != mod_shape.text.strip():
                    unchanged = False
                    break
            # Optionally, compare shape types and count
            if type(orig_shape) != type(mod_shape):
                unchanged = False
                break
        if len(orig_slide.shapes) != len(mod_slide.shapes):
            unchanged = False
            break
    if unchanged:
        return "No extraneous changes in other slides.", 1.0
    else:
        return "Other slides were modified.", 0.0
